using System;
using System.Collections.Generic;
using System.Data.Entity;
using System.Linq;
using System.Net;
using System.Text;
using System.Web.Mvc;

namespace MyStore.Web.Controllers
{
    public class ProductController : Controller
    {
        private readonly StoreDbContext _db = new StoreDbContext();

        public ActionResult Details(int id)
        {
            var product = _db.Products
                .Include(p => p.Reviews)
                .FirstOrDefault(p => p.Id == id);

            if (product == null)
                return HttpNotFound();

            var model = new ProductDetailsViewModel
            {
                ProductId = product.Id,
                ProductName = product.Name,
                Description = product.Description,
                Reviews = product.Reviews
                    .OrderByDescending(r => r.CreatedAtUtc)
                    .Select(r => new ReviewViewModel
                    {
                        AuthorName = r.AuthorName,
                        CreatedAtUtc = r.CreatedAtUtc,
                        HtmlContent = ReviewFormatting.ToSafeHtml(r.Content)
                    })
                    .ToList()
            };

            return View(model);
        }

        protected override void Dispose(bool disposing)
        {
            if (disposing)
                _db.Dispose();

            base.Dispose(disposing);
        }
    }

    public static class ReviewFormatting
    {
        public static string ToSafeHtml(string input)
        {
            if (string.IsNullOrEmpty(input))
                return string.Empty;

            var encoded = WebUtility.HtmlEncode(input);

            encoded = encoded.Replace("[b]", "<strong>")
                             .Replace("[/b]", "</strong>")
                             .Replace("[i]", "<em>")
                             .Replace("[/i]", "</em>");

            return encoded;
        }
    }

    public class ProductDetailsViewModel
    {
        public int ProductId { get; set; }
        public string ProductName { get; set; }
        public string Description { get; set; }
        public List<ReviewViewModel> Reviews { get; set; } = new List<ReviewViewModel>();
    }

    public class ReviewViewModel
    {
        public string AuthorName { get; set; }
        public DateTime CreatedAtUtc { get; set; }
        public string HtmlContent { get; set; }
    }

    public class Product
    {
        public int Id { get; set; }
        public string Name { get; set; }
        public string Description { get; set; }
        public virtual ICollection<Review> Reviews { get; set; } = new List<Review>();
    }

    public class Review
    {
        public int Id { get; set; }
        public int ProductId { get; set; }
        public string AuthorName { get; set; }
        public string Content { get; set; }
        public DateTime CreatedAtUtc { get; set; }
    }

    public class StoreDbContext : DbContext
    {
        public DbSet<Product> Products { get; set; }
        public DbSet<Review> Reviews { get; set; }
    }
}

@model MyStore.Web.Controllers.ProductDetailsViewModel

<h2>@Model.ProductName</h2>
<p>@Model.Description</p>

<section class="reviews">
    <h3>Reviews</h3>

    @if (Model.Reviews == null || !Model.Reviews.Any())
    {
        <p>No reviews yet.</p>
    }
    else
    {
        foreach (var review in Model.Reviews)
        {
            <article class="review">
                <div class="review-meta">
                    <strong>@review.AuthorName</strong>
                    <span>@review.CreatedAtUtc.ToLocalTime().ToString("g")</span>
                </div>
                <div class="review-content">
                    @Html.Raw(review.HtmlContent)
                </div>
            </article>
        }
    }
</section>